@Test
public void testNegativeTimestampTooSmall() {
    // Test that timestamps smaller than Integer.MIN_VALUE are rejected
    try {
        xf.setModifyJavaTime(new Date(1000L * (Integer.MIN_VALUE - 1L)));
        fail("Time too small for signed 32 bits!");
    } catch (final IllegalArgumentException iae) {
        // Expected
    }
}

@Test
public void testValidNegativeTimestamp() {
    // Test that valid negative timestamps (e.g., dates before 1970) work correctly
    final long validNegativeSeconds = -1000000L; // Well within signed 32-bit range
    final long timeMillis = validNegativeSeconds * 1000L;
    final ZipLong time = new ZipLong(validNegativeSeconds);

    xf.setModifyJavaTime(new Date(timeMillis));
    assertEquals(time, xf.getModifyTime());
    assertEquals(timeMillis, xf.getModifyJavaTime().getTime());
}

@Test
public void testBoundaryTimestamps() {
    // Test Integer.MIN_VALUE (should work)
    final long minTimeMillis = Integer.MIN_VALUE * 1000L;
    xf.setModifyJavaTime(new Date(minTimeMillis));
    assertEquals(Integer.MIN_VALUE, xf.getModifyTime().getValue());

    // Test Integer.MAX_VALUE (should work)
    final long maxTimeMillis = Integer.MAX_VALUE * 1000L;
    xf.setModifyJavaTime(new Date(maxTimeMillis));
    assertEquals(Integer.MAX_VALUE, xf.getModifyTime().getValue());
}
